import type { JobsOptions } from 'bullmq';

/**
 * BullMQ queue constants & defaults (README §2.3 resilience, §2.8 Workflow 2 step 1).
 * The queue name is exported as a single constant so the producer (api) and the
 * `@Processor` (worker) cannot drift.
 */
export const ANALYTICS_QUEUE = 'analytics-profile-update';

/** Job name on the analytics queue. */
export const ANALYTICS_JOB = 'profile-update';

/**
 * Default job options — retry on failure with exponential backoff so a transient
 * AI-service outage re-queues the job instead of dropping it (README §2.3).
 */
export const ANALYTICS_JOB_OPTIONS: JobsOptions = {
  attempts: 3,
  backoff: { type: 'exponential', delay: 2000 },
  removeOnComplete: 1000,
  removeOnFail: 5000,
};
